import{_ as t,o as a,c as i,ag as r}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"Best Practices","description":"Learn how to make bamdra-openclaw-memory feel smoother after installation through prompt design, conversation style, and clear explicit rules.","frontmatter":{"title":"Best Practices","description":"Learn how to make bamdra-openclaw-memory feel smoother after installation through prompt design, conversation style, and clear explicit rules."},"headers":[],"relativePath":"guide/best-practices.md","filePath":"guide/best-practices.md","lastUpdated":null}'),l={name:"guide/best-practices.md"};function o(s,e,n,h,c,d){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h1><h2 id="the-real-experience-is-shaped-after-installation" tabindex="-1">The real experience is shaped after installation <a class="header-anchor" href="#the-real-experience-is-shaped-after-installation" aria-label="Permalink to &quot;The real experience is shaped after installation&quot;">​</a></h2><p>The best version of this product is not one where users constantly operate memory directly. It is one where they barely notice the scheduling layer at all, while conversations become smoother, recovery becomes quieter, and continuity survives interruption.</p><h2 id="prompt-design-that-improves-smoothness" tabindex="-1">Prompt design that improves smoothness <a class="header-anchor" href="#prompt-design-that-improves-smoothness" aria-label="Permalink to &quot;Prompt design that improves smoothness&quot;">​</a></h2><p>If you want recall and switching to feel more invisible, your prompt policy should make these expectations explicit:</p><ul><li>treat &quot;remember this&quot; as a durable-fact save signal</li><li>recover earlier context quietly when the user returns to an old thread</li><li>search or recall before asking the user to repeat a stable detail</li><li>avoid narrating internal memory operations unless the user asks</li></ul><h2 id="use-skill-md-to-make-the-engine-smarter" tabindex="-1">Use <code>SKILL.md</code> to make the engine smarter <a class="header-anchor" href="#use-skill-md-to-make-the-engine-smarter" aria-label="Permalink to &quot;Use `SKILL.md` to make the engine smarter&quot;">​</a></h2><p>Beyond the base prompt, <code>SKILL.md</code> is a strong place to teach the engine how to read user intent more reliably.</p><p>This layer is especially useful for clarifying:</p><ul><li>when a message should be treated as &quot;remember this&quot;</li><li>when a message should be treated as &quot;go back to the earlier topic&quot;</li><li>when a shift should be treated as a genuinely new topic</li><li>when recall should happen before asking the user again</li></ul><p>Used well, <code>SKILL.md</code> helps the engine make better intent judgments in normal conversation rather than relying on rigid phrase matching.</p><h2 id="conversation-habits-that-work-well" tabindex="-1">Conversation habits that work well <a class="header-anchor" href="#conversation-habits-that-work-well" aria-label="Permalink to &quot;Conversation habits that work well&quot;">​</a></h2><p>The product feels better when people speak naturally but clearly:</p><ul><li>continue old topics directly instead of replaying the whole background</li><li>express long-lived preferences and constraints in plain language</li><li>mark a hard shift with short language like &quot;new topic&quot; or &quot;back to the earlier thread&quot;</li></ul><h2 id="what-smooth-switching-should-feel-like" tabindex="-1">What smooth switching should feel like <a class="header-anchor" href="#what-smooth-switching-should-feel-like" aria-label="Permalink to &quot;What smooth switching should feel like&quot;">​</a></h2><p>In the ideal case, users do not feel like they are operating a memory system. They simply notice that:</p><ul><li>earlier threads return cleanly</li><li>stable facts show up at the right time</li><li>interruptions do not contaminate the main thread</li></ul><h2 id="ideal-rules-for-explicit-language-triggers" tabindex="-1">Ideal rules for explicit language triggers <a class="header-anchor" href="#ideal-rules-for-explicit-language-triggers" aria-label="Permalink to &quot;Ideal rules for explicit language triggers&quot;">​</a></h2><p>Explicit rules still matter, as long as they support conversation rather than replacing it:</p><ul><li>when the user says &quot;remember this&quot;, prioritize saving a durable fact</li><li>when the user says &quot;go back to that earlier topic&quot;, prioritize topic recovery</li><li>when the user says &quot;this is a new topic&quot;, avoid carrying irrelevant old context forward</li><li>when the user asks &quot;do you still remember&quot;, prioritize recall before asking again</li></ul><h2 id="why-the-dual-model-matters" tabindex="-1">Why the dual model matters <a class="header-anchor" href="#why-the-dual-model-matters" aria-label="Permalink to &quot;Why the dual model matters&quot;">​</a></h2><p>The product relies on dual protection: rules plus natural-language guidance.</p><ul><li>rules provide predictable fallback, explicit boundary handling, and stable fact behavior</li><li>natural-language understanding keeps recovery and switching fluid in ordinary conversation</li></ul><p>That is what makes the product both dependable and smooth.</p>',24)])])}const m=t(l,[["render",o]]);export{p as __pageData,m as default};
